from elasticsearch import Elasticsearch
import json

def execute_dynamic_aggregation(script_code, index_name):
    es = Elasticsearch([{'host': 'localhost', 'port': 9200}])
    
    body = {
        "aggs": {
            "dynamic_agg": {
                "scripted_metric": {
                    "init_script": "state.count = 0",
                    "map_script": script_code,
                    "combine_script": "return state.count",
                    "reduce_script": "int total = 0; for (int i = 0; i < states.length; i++) { total += states[i]; } return total;"
                }
            }
        }
    }
    
    try:
        response = es.search(index=index_name, body=body)
        return response
    except Exception as e:
        return {"error": str(e)}

# Example usage
